/** @param {string} value */
const validateDate = (value) => {
  const [day, month, year] = value.split('/');

  const dayNumber = parseInt(day, 10);
  const monthNumber = parseInt(month, 10);
  const yearNumber = parseInt(year, 10);

  let newValue = value;

  // Validate if first day number greater than 3, auto adjust with 0 before
  if (day?.[0] > '3' && !day?.[1]) {
    newValue = `0${day[0]}`;
  }

  // Validate no value is greater than max valid
  if (dayNumber > 31 || dayNumber === 0) {
    return day[0];
  }

  // Validate if first month number greater than 1, auto adjust with 0 before
  if (month?.[0] > '1' && !month?.[1]) {
    newValue = `${day}/0${month[0]}`;
  }

  // Validate no value is greater than max valid
  if (monthNumber > 12 || monthNumber === 0) {
    return `${day}/${month?.[0] === '1' || month?.[0] === '0' ? month?.[0] : ''}`;
  }

  // Validate day in month is valid
  const daysInMonth = [31, Number(year) % 4 === 0 ? 29 : 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
  if (monthNumber && Number(String(monthNumber)[0]) !== 0 && dayNumber > daysInMonth[monthNumber - 1]) {
    return `${day}/${month[0]}`;
  }

  // Validates year digits
  if (yearNumber === 0) return `${day}/${month}`;
  if (yearNumber) {
    const firstDigit = year?.[0];
    const secondDigit = year?.[1];
    const thirdDigit = year?.[2];
    const fourthDigit = year?.[3];

    if ((firstDigit) && firstDigit !== '1' && firstDigit !== '2') {
      return `${day}/${month}/`;
    }
    if (
      secondDigit
      && !((firstDigit === '1' && secondDigit === '9')
      || (firstDigit === '2' && (secondDigit === '1' || secondDigit === '0')))) {
      return `${day}/${month}/${firstDigit}`;
    }

    if (thirdDigit
      && !((secondDigit === '9' || secondDigit === '0')
      || (secondDigit === '1' && thirdDigit === '0'))) {
      return `${day}/${month}/${firstDigit}${secondDigit}`;
    }

    if (fourthDigit
      && !(
        secondDigit === '9' || secondDigit === '0' || (secondDigit === '1' && fourthDigit === '0')
      )) {
      return `${day}/${month}/${firstDigit}${secondDigit}${thirdDigit}`;
    }
  }

  return newValue;
};

/** @param {string} value */
const validateDateTime = (value) => {
  const [dateStr, timeStr] = value.split(' ');
  const [hour, minute, seconds] = timeStr ? timeStr.split(':') : [];

  const dateValue = validateDate(dateStr);

  const newValue = timeStr ? `${dateValue} ${timeStr}` : dateValue;

  // Validate no value is greater than max valid
  if (parseInt(hour?.[0], 10) > 2) return dateValue;

  const hourNumber = parseInt(hour, 10);
  if (hourNumber > 23) return `${dateValue} ${hour[0]}`;

  if (parseInt(minute?.[0], 10) > 5) return `${dateValue} ${hour}`;

  if (parseInt(seconds?.[0], 10) > 5) return `${dateValue} ${hour}:${minute}`;

  return newValue;
};

export { validateDate, validateDateTime };
